int target = 5;
int low = 0;
int high = arr.length - 1;

while (low <= high) {
  int mid = (low + high) / 2;
  if (arr[mid] == target) {
    System.out.println("Target found at index " + mid);
    break;
  } else if (arr[mid] < target) {
    low = mid + 1;
  } else {
    high = mid - 1;
  }
}
```

